sql:
SELECT o.outlet_name, m.manager_name
FROM outlets o
INNER JOIN managers m ON o.manager_id = m.manager_id;

SELECT SUM(quantity) AS Total_Quantity_Supplied
FROM fuel_supplies
WHERE supplier_id = 0;

external_knowledge:
- 'fuel station' is a metaphor for 'outlet';
- 'sipped various drinks from the well' metaphorically refers to consuming different fuel types;
- 'nectar' metaphorically refers to types of fuel;
- 'the day they quenched their thirst' refers to the date of fuel consumption.

sql:
SELECT district, COUNT(*) AS outlet_count
FROM outlets
GROUP BY district;

SELECT o.outlet_name, fc.quantity_consumed
FROM outlets o
INNER JOIN fuel_consumption fc ON o.outlet_id = fc.outlet_id;

SELECT supply_id, outlet_id, fuel_type_id, quantity
FROM fuel_supplies
WHERE quantity > 50;

external_knowledge:
- 'places' refers to 'outlets';
- 'types of fuel' refers to 'fuel types';
- 'how much of each type is supplied' refers to 'quantity of fuel'.

sql:
SELECT users.username, users.role
FROM users 
INNER JOIN suppliers ON users.username = suppliers.supplier_email;

SELECT u.username, u.role
FROM users u
WHERE u.role IN (
    SELECT DISTINCT 'manager' || m.manager_id
    FROM managers m
);
